class NonceStore:
    """Manages authentication nonces with expiration and single-use enforcement."""

    def __init__(self, expiry_seconds: int = 300):
        self._nonces: Dict[str, Nonce] = {}
        self._expiry_seconds = expiry_seconds

    def generate(self, address: str) -> str:
        address = address.lower()
        self._cleanup_expired()

        # Invalidate any existing nonces for this address
        for nonce_id, nonce in list(self._nonces.items()):
            if nonce.address == address and not nonce.used:
                nonce.used = True

        nonce_value = secrets.token_hex(32)
        nonce_id = hashlib.sha256(
            f"{address}:{nonce_value}:{time.time()}".encode()
        ).hexdigest()

        self._nonces[nonce_id] = Nonce(
            value=nonce_value,
            address=address,
            created_at=time.time()
        )

        return nonce_value

    def validate_and_consume(self, address: str, nonce_value: str) -> bool:
        address = address.lower()
        self._cleanup_expired()

        for nonce_id, nonce in self._nonces.items():
            if (nonce.address == address
                    and nonce.value == nonce_value
                    and not nonce.used):
                elapsed = time.time() - nonce.created_at
                if elapsed <= self._expiry_seconds:
                    nonce.used = True
                    return True
                else:
                    nonce.used = True
                    return False

        return False

    def _cleanup_expired(self):
        now = time.time()
        expired = [
            nid for nid, n in self._nonces.items()
            if now - n.created_at > self._expiry_seconds * 2 or n.used
        ]
        # Keep used nonces for a short replay-prevention window
        for nid in expired:
            nonce = self._nonces[nid]
            if nonce.used and now - nonce.created_at > self._expiry_seconds * 2:
                del self._nonces[nid]
            elif not nonce.used and now - nonce.created_at > self._expiry_seconds:
                del self._nonces[nid]


class SessionStore:
    """Manages authenticated sessions."""

    def __init__(self, session_duration_hours: int = 24):
        self._sessions: Dict[str, Session] = {}
        self._session_duration = session_duration_hours * 3600

    def create(self, address: str) -> str:
        address = address.lower()
        self._cleanup_expired()

        # Invalidate existing sessions for this address
        for sid, session in self._sessions.items():
            if session.address == address and session.is_valid:
                session.is_valid = False

        token = secrets.token_urlsafe(48)
        token_hash = self._hash_token(token)
        now = time.time()

        self._sessions[token_hash] = Session(
            token=token_hash,
            address=address,
            created_at=now,
            expires_at=now + self._session_duration
        )

        return token

    def validate(self, token: str) -> Optional[str]:
        token_hash = self._hash_token(token)
        session = self._sessions.get(token_hash)

        if session is None:
            return None
        if not session.is_valid:
            return None
        if time.time() > session.expires_at:
            session.is_valid = False
            return None

        return session.address

    def invalidate(self, token: str) -> bool:
        token_hash = self._hash_token(token)
        session = self._sessions.get(token_hash)
        if session and session.is_valid:
            session.is_valid = False
            return True
        return False

    def _hash_token(self, token: str) -> str:
        return hashlib.sha256(token.encode()).hexdigest()

    def _cleanup_expired(self):
        now = time.time()
        expired = [
            sid for sid, s in self._sessions.items()
            if now > s.expires_at or not s.is_valid
        ]
        for sid in expired:
            del self._sessions[sid]


class RateLimiter:
    """Rate limiter to prevent brute-force attacks."""

    def __init__(self, max_attempts: int = 5, window_seconds: int = 300,
                 block_seconds: int = 900):
        self._entries: Dict[str, RateLimitEntry] = {}
        self._max_attempts = max_attempts
        self._window_seconds = window_seconds
        self._block_seconds = block_seconds

    def is_allowed(self, key: str) -> bool:
        now = time.time()
        entry = self._entries.get(key)

        if entry is None:
            self._entries[key] = RateLimitEntry(
                attempts=1,
                first_attempt=now
            )
            return True

        # Check if currently blocked
        if entry.blocked_until > now:
            return False

        # Reset window if expired
        if now - entry.first_attempt > self._window_seconds:
            entry.attempts = 1
            entry.first_attempt = now
            entry.blocked_until = 0.0
            return True

        entry.attempts += 1

        if entry.attempts > self._max_attempts:
            entry.blocked_until = now + self._block_seconds
            logger.warning(f"Rate limit exceeded for key: {key[:16]}...")
            return False

        return True

    def reset(self, key: str):
        if key in self._entries:
            del self._entries[key]


