def is_valid_ethereum_address(address: str) -> bool:
    """Validate Ethereum address format."""
    if not address or not isinstance(address, str):
        return False
    if not address.startswith('0x'):
        return False
    if len(address) != 42:
        return False
    try:
        int(address, 16)
    except ValueError:
        return False
    return True


def build_auth_message(address: str, nonce: str) -> str:
    """
    Build a standardized authentication message.
    Uses a domain-specific prefix to prevent signature reuse across applications.
    """
    domain = os.environ.get('AUTH_DOMAIN', 'localhost')
    timestamp = datetime.utcnow().strftime('%Y-%m-%d')
    return (
        f"Welcome to Web3 Auth\n\n"
        f"Domain: {domain}\n"
        f"Address: {address.lower()}\n"
        f"Nonce: {nonce}\n"
        f"Date: {timestamp}\n\n"
        f"Sign this message to authenticate. "
        f"This will not trigger a blockchain transaction."
    )


def verify_signature(message: str, signature: str, expected_address: str) -> bool:
    """
    Verify an Ethereum signature against an expected address.
    Uses constant-time comparison to prevent timing attacks.
    """
    try:
        if not signature or not isinstance(signature, str):
            return False
        if not signature.startswith('0x'):
            return False
        if len(signature) != 132:  # 0x + 130 hex chars = 65 bytes
            return False

        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(
            encoded_message,
            signature=signature
        )

        # Constant-time comparison to prevent timing attacks
        return secrets.compare_digest(
            recovered_address.lower(),
            expected_address.lower()
        )
    except Exception as e:
        logger.error(f"Signature verification error: {type(e).__name__}")
        return False


def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid authorization header'}), 401

        token = auth_header[7:]
        address = session_store.validate(token)

        if address is None:
            return jsonify({'error': 'Invalid or expired session'}), 401

        request.authenticated_address = address
        return f(*args, **kwargs)

    return decorated


