@app.route('/auth/nonce', methods=['POST'])
def request_nonce():
    """
    Request a nonce for authentication.
    The client must sign a message containing this nonce.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    address = data.get('address', '').strip()

    if not is_valid_ethereum_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Rate limit nonce requests by address
    rate_key = f"nonce:{address.lower()}"
    if not rate_limiter.is_allowed(rate_key):
        return jsonify({'error': 'Too many requests. Please try again later.'}), 429

    # Normalize address using checksum
    try:
        checksum_address = Web3.to_checksum_address(address)
    except Exception:
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    nonce = nonce_store.generate(checksum_address)
    message = build_auth_message(checksum_address, nonce)

    logger.info(f"Nonce generated for address: {checksum_address[:10]}...")

    return jsonify({
        'nonce': nonce,
        'message': message,
        'address': checksum_address
    }), 200


@app.route('/auth/verify', methods=['POST'])
def verify_and_authenticate():
    """
    Verify a signed message and create an authenticated session.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Request body required'}), 400

    address = data.get('address', '').strip()
    signature = data.get('signature', '').strip()
    nonce = data.get('nonce', '').strip()

    # Validate inputs
    if not all([address, signature, nonce]):
        return jsonify({'error': 'address, signature, and nonce are required'}), 400

    if not is_valid_ethereum_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Rate limit verification attempts by address and IP
    client_ip = request.remote_addr or 'unknown'
    rate_key_addr = f"verify:{address.lower()}"
    rate_key_ip = f"verify_ip:{client_ip}"

    if not rate_limiter.is_allowed(rate_key_addr):
        logger.warning(f"Rate limit hit for address: {address[:10]}...")
        return jsonify({'error': 'Too many verification attempts. Please try again later.'}), 429

    if not rate_limiter.is_allowed(rate_key_ip):
        logger.warning(f"Rate limit hit for IP: {client_ip}")
        return jsonify({'error': 'Too many verification attempts. Please try again later.'}), 429

    try:
        checksum_address = Web3.to_checksum_address(address)
    except Exception:
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Validate and consume the nonce (single-use)
    if not nonce_store.validate_and_consume(checksum_address, nonce):
        logger.warning(f"Invalid or expired nonce for address: {checksum_address[:10]}...")
        return jsonify({'error': 'Invalid or expired nonce. Please request a new one.'}), 401

    # Reconstruct the expected message
    message = build_auth_message(checksum_address, nonce)

    # Verify the signature
    if not verify_signature(message, signature, checksum_address):
        logger.warning(f"Signature verification failed for address: {checksum_address[:10]}...")
        return jsonify({'error': 'Signature verification failed'}), 401

    # Authentication successful - create session
    session_token = session_store.create(checksum_address)

    # Reset rate limiter on successful auth
    rate_limiter.reset(rate_key_addr)
    rate_limiter.reset(rate_key_ip)

    logger.info(f"Authentication successful for address: {checksum_address[:10]}...")

    return jsonify({
        'authenticated': True,
        'address': checksum_address,
        'token': session_token,
        'expires_in': 86400  # 24 hours in seconds
    }), 200


